class Solution:
    def lastStoneWeight(self, stones):
        s = list(stones)
        while len(s) > 1:
            s.sort()
            y = s.pop()
            x = s.pop()
            if y - x > 0:
                s.append(y - x)
        return s[0] if s else 0

