var lastStoneWeight = function(stones) {
    const s = stones.slice();
    while (s.length > 1) {
        s.sort((a, b) => a - b);
        const y = s.pop();
        const x = s.pop();
        if (y - x > 0) s.push(y - x);
    }
    return s.length ? s[0] : 0;
};
